Take this example script:
```python
def no_arg_func():
    pass


def arg_func(name):
    pass


def named_arg_func(name=None):
    pass


def accept_name(func):
    func.__accept_name__ = True
    return func


@accept_name
def decorated_func(name=None):
    pass


def try_except_no_arg_func(func):
    try:
        func()
    except TypeError:
        # Won't happen
        pass


def try_except_args_func(func):
    try:
        func(True)
    except TypeError:
        func()


def try_except_named_arg_func(func):
    try:
        func(name=True)
    except TypeError:
        func()


def try_decorated_func(func):
    try:
        func.__accept_name__
        func(name=True)
    except AttributeError:
        func()


def try_decorated_func_has_attr(func):
    if hasattr(func, '.__accept_name__'):
        func(name=True)
    else:
        func()


def main():
    import timeit
    # Cold start
    t1 = timeit.timeit('try_except_no_arg_func(no_arg_func)', setup='from __main__ import try_except_no_arg_func, no_arg_func')
    t2 = timeit.timeit('try_except_args_func(arg_func)', setup='from __main__ import try_except_args_func, arg_func')
    t3 = timeit.timeit('try_except_named_arg_func(named_arg_func)', setup='from __main__ import try_except_named_arg_func, named_arg_func')
    t4 = timeit.timeit('try_decorated_func(no_arg_func)', setup='from __main__ import try_decorated_func, no_arg_func')
    t5 = timeit.timeit('try_decorated_func(decorated_func)', setup='from __main__ import try_decorated_func, decorated_func')
    t6 = timeit.timeit('try_decorated_func_has_attr(no_arg_func)', setup='from __main__ import try_decorated_func_has_attr, no_arg_func')
    t7 = timeit.timeit('try_decorated_func_has_attr(decorated_func)', setup='from __main__ import try_decorated_func_has_attr, decorated_func')
    # Re-run
    t1 = timeit.timeit('try_except_no_arg_func(no_arg_func)', setup='from __main__ import try_except_no_arg_func, no_arg_func')
    t2 = timeit.timeit('try_except_args_func(arg_func)', setup='from __main__ import try_except_args_func, arg_func')
    t3 = timeit.timeit('try_except_named_arg_func(named_arg_func)', setup='from __main__ import try_except_named_arg_func, named_arg_func')
    t4 = timeit.timeit('try_decorated_func(no_arg_func)', setup='from __main__ import try_decorated_func, no_arg_func')
    t5 = timeit.timeit('try_decorated_func(decorated_func)', setup='from __main__ import try_decorated_func, decorated_func')
    t6 = timeit.timeit('try_decorated_func_has_attr(no_arg_func)', setup='from __main__ import try_decorated_func_has_attr, no_arg_func')
    t7 = timeit.timeit('try_decorated_func_has_attr(decorated_func)', setup='from __main__ import try_decorated_func_has_attr, decorated_func')

    print('                    Old behavior:', t1)
    print('           Try/Execpt using args:', t2)
    print('Try/Except using named arguments:', t3)
    print('              Non decorated func:', t4)
    print('                  Decorated func:', t5)
    print('     Non decorated func(hasattr):', t6)
    print('         Decorated func(hasattr):', t7)


if __name__ == "__main__":
    main()
```
